using System.Security.Claims;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_be3b59dbd06543328cbe2f65f4546801.Auth;

/// <summary>
/// Server-side provider that simulates a logged-in user with hardcoded claims.
/// </summary>
public class FakeAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _state = Task.FromResult(
        new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity(
            new[]
            {
                new Claim(ClaimTypes.Name, "bob@example.com"),
                new Claim(ClaimTypes.Email, "bob@example.com"),
                new Claim(ClaimTypes.Role, "User"),
                new Claim(ClaimTypes.Role, "Editor"),
            },
            authenticationType: "FakeAuth"))));

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _state;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;

namespace sv_be3b59dbd06543328cbe2f65f4546801.Auth;

/// <summary>
/// Subscribes to the server-side <see cref="AuthenticationStateProvider"/> and
/// persists user info into <see cref="PersistentComponentState"/> so the WASM
/// client can rehydrate the identity after the interactive runtime activates.
/// </summary>
public class PersistingAuthenticationStateProvider : IHostEnvironmentAuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _persistentState;
    private readonly AuthenticationStateProvider _authProvider;
    private PersistingComponentStateSubscription _subscription;
    private Task<AuthenticationState>? _authStateTask;

    public PersistingAuthenticationStateProvider(
        PersistentComponentState persistentState,
        AuthenticationStateProvider authProvider)
    {
        _persistentState = persistentState;
        _authProvider = authProvider;

        // Hook into the pre-render persistence pipeline.
        _subscription = _persistentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveAuto);

        // Proxy through to the real provider so server components still work.
        _authProvider.AuthenticationStateChanged += OnAuthenticationStateChanged;
    }

    public void SetAuthenticationState(Task<AuthenticationState> authenticationStateTask)
    {
        _authStateTask = authenticationStateTask;
    }

    private void OnAuthenticationStateChanged(Task<AuthenticationState> task)
    {
        _authStateTask = task;
    }

    private async Task OnPersistingAsync()
    {
        var authState = await (_authStateTask ?? _authProvider.GetAuthenticationStateAsync());
        var principal = authState.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            var claims = principal.Claims.Select(c => new ClaimData(c.Type, c.Value)).ToArray();
            _persistentState.PersistAsJson(nameof(ClaimData), claims);
        }
    }

    public void Dispose()
    {
        _subscription.Dispose();
        _authProvider.AuthenticationStateChanged -= OnAuthenticationStateChanged;
    }
}

namespace sv_be3b59dbd06543328cbe2f65f4546801.Auth;

/// <summary>
/// Serializable claim representation shared between server and client projects.
/// </summary>
public record ClaimData(string Type, string Value);

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_be3b59dbd06543328cbe2f65f4546801.Client.Auth;

/// <summary>
/// Client-side (WASM) provider that rehydrates the user identity from claims
/// persisted by the server during pre-rendering.
/// </summary>
public class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authState;

    public PersistentAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        if (persistentState.TryTakeFromJson<ClaimData[]>(nameof(ClaimData), out var claimData) &&
            claimData is { Length: > 0 })
        {
            var claims = claimData.Select(c => new Claim(c.Type, c.Value));
            var identity = new ClaimsIdentity(claims, "PersistentAuth");
            _authState = Task.FromResult(new AuthenticationState(new ClaimsPrincipal(identity)));
        }
        else
        {
            _authState = _unauthenticated;
        }
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authState;
}

/// <summary>
/// Serializable claim representation — must match the server-side definition.
/// </summary>
public record ClaimData(string Type, string Value);

@page "/profile"
@rendermode InteractiveAuto
@using Microsoft.AspNetCore.Components.Authorization
@using System.Security.Claims

<PageTitle>Profile</PageTitle>

<h1>Profile</h1>

<AuthorizeView>
    <Authorized>
        <p><strong>Name:</strong> @context.User.Identity?.Name</p>
        <h4>Roles</h4>
        <ul>
            @foreach (var role in context.User.Claims
                .Where(c => c.Type == ClaimTypes.Role)
                .Select(c => c.Value))
            {
                <li>@role</li>
            }
        </ul>
    </Authorized>
    <NotAuthorized>
        <p>You are not logged in.</p>
    </NotAuthorized>
</AuthorizeView>

@page "/editor"
@rendermode InteractiveAuto
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize(Roles = "Editor")]

<PageTitle>Editor</PageTitle>

<h1>Editor Page</h1>

<p>Welcome, editor! You have the <strong>Editor</strong> role.</p>

